// Process and enhance telemetry data
msg.enhanced = {
  protocol: 'MQTT',
  gateway_timestamp: Date.now(),
  floor: msg.topic.split('/')[2],
  room_id: msg.payload.sensor_id,
  temperature: msg.payload.temperature,
  humidity: msg.payload.humidity,
  occupancy: msg.payload.occupancy,
  hvac_mode: msg.payload.hvac_mode,
  source_topic: msg.topic
};
return msg;

// Edge thinning - aggregate every 60 seconds
const context = this || {};
const floor = msg.enhanced.floor;

if (!context.floorData) {
  context.floorData = {};
}

if (!context.floorData[floor]) {
  context.floorData[floor] = {
    temperatures: [],
    humidity: [],
    occupancy: [],
    lastReset: Date.now()
  };
}

const data = context.floorData[floor];
const now = Date.now();

// Add current data
data.temperatures.push(msg.enhanced.temperature);
data.humidity.push(msg.enhanced.humidity);
data.occupancy.push(msg.enhanced.occupancy ? 1 : 0);

// Check if 60 seconds have passed
if (now - data.lastReset >= 60000) {
  // Calculate averages
  const avgTemp = data.temperatures.reduce((a, b) => a + b, 0) / data.temperatures.length;
  const avgHumidity = data.humidity.reduce((a, b) => a + b, 0) / data.humidity.length;
  const avgOccupancy = data.occupancy.reduce((a, b) => a + b, 0) / data.occupancy.length;

  // Create aggregated message
  msg.aggregated = {
    floor: floor,
    timestamp: now,
    avg_temperature: Math.round(avgTemp * 10) / 10,
    avg_humidity: Math.round(avgHumidity * 10) / 10,
    avg_occupancy: Math.round(avgOccupancy * 100),
    sample_count: data.temperatures.length,
    gateway_id: 'floor-' + floor + '-gateway'
  };

  // Reset data
  data.temperatures = [];
  data.humidity = [];
  data.occupancy = [];
  data.lastReset = now;

  return msg;
}

// Don't send message if not time yet
return null;

// Translate HVAC command to CoAP
const topic_parts = msg.topic.split('/');
const room_id = topic_parts[3];
const floor = topic_parts[2];

// Map room to CoAP port (simplified)
const room_num = parseInt(room_id.split('-r')[1]);
const coap_port = 5683 + room_num - 1;

msg.coap_command = {
  hvac_mode: msg.payload.hvac_mode || msg.payload.hvac,
  timestamp: Date.now(),
  source: 'mqtt-gateway'
};

msg.coap_url = `coap://localhost:${coap_port}/actuators`;
msg.room_id = room_id;
msg.floor = floor;

return msg;

